# Category: race_condition

using System;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;
using System.Security.Cryptography;
using System.Text;

public class EventBookingContext : DbContext
{
    public DbSet<Event> Events { get; set; }
    public DbSet<Ticket> Tickets { get; set; }

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
        => optionsBuilder.UseSqlServer("Data Source=(localdb)\\mssqllocaldb;Initial Catalog=EventBookingDB");

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Event>().ToTable("Events");
        modelBuilder.Entity<Ticket>().ToTable("Tickets");
    }
}

public class Event
{
    public int Id { get; set; }
    public string Name { get; set; }
    public int Capacity { get; set; }
}

public class Ticket
{
    public int Id { get; set; }
    public int EventId { get; set; }
    public Event Event { get; set; }
    public bool IsAvailable { get; set; }
}

public class EventBookingService
{
    private readonly EventBookingContext _context;

    public EventBookingService(EventBookingContext context)
        => _context = context;

    public async Task<bool> PurchaseTicketsAsync(int eventId, int quantity, string userId)
    {
        var eventEntity = await _context.Events.FindAsync(eventId);
        if (eventEntity == null) return false;

        var tickets = await _context.Tickets
            .Where(t => t.EventId == eventId && t.IsAvailable)
            .Take(quantity)
            .ToListAsync();

        if (tickets.Count < quantity) return false;

        foreach (var ticket in tickets)
        {
            ticket.IsAvailable = false;
        }

        try
        {
            await _context.SaveChangesAsync();
            return true;
        }
        catch (DbUpdateConcurrencyException ex)
        {
            Console.WriteLine($"Concurrency error: {ex.Message}");
            return false;
        }
    }
}